void simdunpack_u16_delta_carry(const __m256i *in, uint16_t *out, const uint32_t bit, __m256i* carry, __m256i* sum) {
  switch (bit) {
  case 0: {
    /* b==0: every value is 0 (= zigzag delta of 0 from prev); */
    /* prefix sums of zeros yield carry repeated; carry is unchanged. */
    size_t i;
    for (i = 0; i < 16; ++i) {
      agg_pipeline_carry_simdcomp(_mm256_setzero_si256(), carry, sum);
    }
    /* SIMD_nullunpacker16(in, out); */
    break;
  }
  case 1:
    __SIMD_fastunpack1_16_delta_carry(in, out, sum, carry);
    break;

  case 2:
    __SIMD_fastunpack2_16_delta_carry(in, out, sum, carry);
    break;

  case 3:
    __SIMD_fastunpack3_16_delta_carry(in, out, sum, carry);
    break;

  case 4:
    __SIMD_fastunpack4_16_delta_carry(in, out, sum, carry);
    break;

  case 5:
    __SIMD_fastunpack5_16_delta_carry(in, out, sum, carry);
    break;

  case 6:
    __SIMD_fastunpack6_16_delta_carry(in, out, sum, carry);
    break;

  case 7:
    __SIMD_fastunpack7_16_delta_carry(in, out, sum, carry);
    break;

  case 8:
    __SIMD_fastunpack8_16_delta_carry(in, out, sum, carry);
    break;

  case 9:
    __SIMD_fastunpack9_16_delta_carry(in, out, sum, carry);
    break;

  case 10:
    __SIMD_fastunpack10_16_delta_carry(in, out, sum, carry);
    break;

  case 11:
    __SIMD_fastunpack11_16_delta_carry(in, out, sum, carry);
    break;

  case 12:
    __SIMD_fastunpack12_16_delta_carry(in, out, sum, carry);
    break;

  case 13:
    __SIMD_fastunpack13_16_delta_carry(in, out, sum, carry);
    break;

  case 14:
    __SIMD_fastunpack14_16_delta_carry(in, out, sum, carry);
    break;

  case 15:
    __SIMD_fastunpack15_16_delta_carry(in, out, sum, carry);
    break;

  case 16:
    __SIMD_fastunpack16_16_delta_carry(in, out, sum, carry);
    break;

  default:
    break;
  }
}
__m256i *simdpack_shortlength_u16(const uint16_t *in, int length, __m256i *out,
                                   const uint32_t bit) {
  int k;
  int inwordpointer;
  __m256i P;
  uint32_t firstpass;
  if (bit == 0)
    return out;
  if (bit == 16) {
    memcpy(out, in, length * sizeof(uint16_t));
    return (__m256i *)((uint16_t *)out + length);
  }
  inwordpointer = 0;
  P = _mm256_setzero_si256();
  for (k = 0; k < length / 16; ++k) {
    __m256i value = _mm256_loadu_si256(((const __m256i *)in + k));
    P = _mm256_or_si256(P, _mm256_slli_epi16(value, inwordpointer));
    firstpass = 16 - inwordpointer;
    if (bit < firstpass) {
      inwordpointer += bit;
    } else {
      _mm256_storeu_si256(out++, P);
      P = _mm256_srli_epi16(value, firstpass);
      inwordpointer = bit - firstpass;
    }
  }
  if (length % 16 != 0) {
    uint16_t buffer[16];
    __m256i value;
    for (k = 0; k < (length % 16); ++k) {
      buffer[k] = in[length / 16 * 16 + k];
    }
    for (k = (length % 16); k < 16; ++k) {
      buffer[k] = 0;
    }
    value = _mm256_loadu_si256((__m256i *)buffer);
    P = _mm256_or_si256(P, _mm256_slli_epi16(value, inwordpointer));
    firstpass = 16 - inwordpointer;
    if (bit < firstpass) {
      inwordpointer += bit;
    } else {
      _mm256_storeu_si256(out++, P);
      P = _mm256_srli_epi16(value, firstpass);
      inwordpointer = bit - firstpass;
    }
  }
  if (inwordpointer != 0) {
    _mm256_storeu_si256(out++, P);
  }
  return out;
}

const __m256i *simdunpack_shortlength_u16(const __m256i *in, int length,
                                           uint16_t *out, const uint32_t bit) {
  int k;
  __m256i maskbits;
  int inwordpointer;
  __m256i P;
  if (length == 0)
    return in;
  if (bit == 0) {
    for (k = 0; k < length; ++k) {
      out[k] = 0;
    }
    return in;
  }
  if (bit == 16) {
    memcpy(out, in, length * sizeof(uint16_t));
    return (const __m256i *)((uint16_t *)in + length);
  }
  maskbits = _mm256_set1_epi16((1U << bit) - 1);
  inwordpointer = 0;
  P = _mm256_loadu_si256((__m256i *)in);
  ++in;
  if (length % 16 == 0) {
    for (k = 0; k + 1 < length / 16; ++k) {
      __m256i answer = _mm256_srli_epi16(P, inwordpointer);
      const uint32_t firstpass = 16 - inwordpointer;
      if (bit < firstpass) {
        inwordpointer += bit;
      } else {
        P = _mm256_loadu_si256((__m256i *)in);
        ++in;
        answer = _mm256_or_si256(_mm256_slli_epi16(P, firstpass), answer);
        inwordpointer = bit - firstpass;
      }
      answer = _mm256_and_si256(maskbits, answer);
      _mm256_storeu_si256((__m256i *)out, answer);
      out += 16;
    }
    if (k < length / 16) {
      __m256i answer = _mm256_srli_epi16(P, inwordpointer);
      const uint32_t firstpass = 16 - inwordpointer;
      if (bit < firstpass) {
        inwordpointer += bit;
      } else if (bit == firstpass) {
        inwordpointer = 0;
      } else {
        P = _mm256_loadu_si256((__m256i *)in);
        ++in;
        answer = _mm256_or_si256(_mm256_slli_epi16(P, firstpass), answer);
        inwordpointer = bit - firstpass;
      }
      answer = _mm256_and_si256(maskbits, answer);
      _mm256_storeu_si256((__m256i *)out, answer);
      out += 16;
    }
  } else {
    for (k = 0; k < length / 16; ++k) {
      __m256i answer = _mm256_srli_epi16(P, inwordpointer);
      const uint32_t firstpass = 16 - inwordpointer;
      if (bit < firstpass) {
        inwordpointer += bit;
      } else {
        P = _mm256_loadu_si256((__m256i *)in);
        ++in;
        answer = _mm256_or_si256(_mm256_slli_epi16(P, firstpass), answer);
        inwordpointer = bit - firstpass;
      }
      answer = _mm256_and_si256(maskbits, answer);
      _mm256_storeu_si256((__m256i *)out, answer);
      out += 16;
    }
    uint16_t buffer[16];
    __m256i answer = _mm256_srli_epi16(P, inwordpointer);
    const uint32_t firstpass = 16 - inwordpointer;
    if (bit < firstpass) {
      inwordpointer += bit;
    } else if (bit == firstpass) {
      inwordpointer = 0;
    } else {
      P = _mm256_loadu_si256((__m256i *)in);
      ++in;
      answer = _mm256_or_si256(_mm256_slli_epi16(P, firstpass), answer);
      inwordpointer = bit - firstpass;
    }
    answer = _mm256_and_si256(maskbits, answer);
    _mm256_storeu_si256((__m256i *)buffer, answer);
    for (k = 0; k < (length % 16); ++k) {
      *out = buffer[k];
      ++out;
    }
  }
  return in;
}

/* returns the integer logarithm of v (bit width) for uint16 */
static uint32_t bits_u16(const uint16_t v) {
  return v == 0 ? 0 : 32 - __builtin_clz((uint32_t)v);
}

static uint32_t oras_u16(const __m256i accumulator) {
  /* Horizontal OR of 16 uint16 lanes into a single uint16 value */
  __m128i lo = _mm256_castsi256_si128(accumulator);
  __m128i hi = _mm256_extracti128_si256(accumulator, 1);
  __m128i combined = _mm_or_si128(lo, hi);
  const __m128i _tmp1 = _mm_or_si128(
      _mm_srli_si128(combined, 8), combined);
  const __m128i _tmp2 = _mm_or_si128(
      _mm_srli_si128(_tmp1, 4), _tmp1);
  const __m128i _tmp3 = _mm_or_si128(
      _mm_srli_si128(_tmp2, 2), _tmp2);
  return (uint16_t)_mm_extract_epi16(_tmp3, 0);
}


uint32_t maxbits_length_u16(const uint16_t *in, size_t length) {
  size_t k;
  size_t lengthdividedby16 = length / 16;
  size_t offset = lengthdividedby16 * 16;
  uint32_t bigxor = 0;
  if (lengthdividedby16 > 0) {
    const __m256i *pin = (const __m256i *)(in);
    __m256i accumulator = _mm256_loadu_si256(pin);
    k = 1;
    for (; 16 * k < 16 * lengthdividedby16; ++k) {
      __m256i newvec = _mm256_loadu_si256(pin + k);
      accumulator = _mm256_or_si256(accumulator, newvec);
    }
    bigxor = oras_u16(accumulator);
  }
  for (k = offset; k < length; ++k)
    bigxor |= in[k];
  return bits_u16((uint16_t)bigxor);
}

int simdpack_compressedbytes_u16(int length, const uint32_t bit) {
  if (bit == 0)
    return 0;
  if (bit == 16) {
    return length * sizeof(uint16_t);
  }
  /* Each group of 16 uint16 lanes packs to (16 * bit) bits = bit bytes per group.
     Total groups = (length + 15) / 16.  Round up to __m256i boundary. */
  return (((length + 15) / 16) * bit + 15) / 16 * sizeof(__m256i);
}

__m256i *simdpack_length_u16(const uint16_t *in, size_t length, __m256i *out,
                              const uint32_t bit) {
  size_t k;
  for (k = 0; k < length / SIMDBlockSize_u16; ++k) {
    simdpack_u16(in, out, bit);
    in += SIMDBlockSize_u16;
    out += bit;
  }
  return simdpack_shortlength_u16(in, length % SIMDBlockSize_u16, out, bit);
}

const __m256i *simdunpack_length_u16(const __m256i *in, size_t length,
                                      uint16_t *out, const uint32_t bit,
                                      uint32_t *outsum) {
  __m256i sum = _mm256_setzero_si256();
  size_t k;
  for (k = 0; k < length / SIMDBlockSize_u16; ++k) {
    simdunpack_u16(in, out, bit, &sum);
    out += SIMDBlockSize_u16;
    in += bit;
  }
  /* 256-bit horizontal reduction */
  __m128i lo = _mm256_castsi256_si128(sum);
  __m128i hi = _mm256_extracti128_si256(sum, 1);
  __m128i s = _mm_add_epi32(lo, hi);
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(1,0,3,2)));
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(2,3,0,1)));

  uint32_t finalsum = (uint32_t)_mm_cvtsi128_si32(s);

  /* Handle remainder with scalar sum */
  size_t remainder = length % SIMDBlockSize_u16;
  if (remainder > 0) {
    in = simdunpack_shortlength_u16(in, remainder, out, bit);
    size_t i;
    for (i = 0; i < remainder; ++i) {
      finalsum += out[i];
    }
  }
  *outsum = finalsum;
  return in;
}

/* LOCAL delta variant: SIMD blocks run zigzag_dec + per-OutReg prefix sum +
   aggregate (no inter-OutReg carry). Tail does scalar zigzag-decode + prefix
   sum, with prev resetting every 16 elements (rounded_length is a multiple
   of 16 so the tail starts at a 16-boundary). */
const __m256i *simdunpack_length_u16_delta_local(const __m256i *in,
                                                  size_t length, uint16_t *out,
                                                  const uint32_t bit,
                                                  uint32_t *outsum) {
  __m256i sum = _mm256_setzero_si256();
  size_t k;
  for (k = 0; k < length / SIMDBlockSize_u16; ++k) {
    simdunpack_u16_delta_local(in, out, bit, &sum);
    out += SIMDBlockSize_u16;
    in += bit;
  }
  /* 256-bit horizontal reduction */
  __m128i lo = _mm256_castsi256_si128(sum);
  __m128i hi = _mm256_extracti128_si256(sum, 1);
  __m128i s = _mm_add_epi32(lo, hi);
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(1,0,3,2)));
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(2,3,0,1)));

  uint32_t finalsum = (uint32_t)_mm_cvtsi128_si32(s);

  /* Tail: scalar un-zigzag + un-delta with prev resetting every 16 elements. */
  size_t remainder = length % SIMDBlockSize_u16;
  if (remainder > 0) {
    in = simdunpack_shortlength_u16(in, remainder, out, bit);
    uint16_t prev = 0;
    size_t i;
    for (i = 0; i < remainder; ++i) {
      if ((i & 15) == 0) prev = 0;
      uint16_t delta = ZigzagDec16_simdcomp(out[i]);
      uint16_t cur = (uint16_t)(prev + delta);
      finalsum += cur;
      prev = cur;
    }
  }
  *outsum = finalsum;
  return in;
}

/* CARRY delta variant: SIMD blocks thread a broadcast-carry __m256i across
   OutRegs/blocks. Tail scalar continues the chain by seeding prev from the
   last broadcast-carry value. */
const __m256i *simdunpack_length_u16_delta_carry(const __m256i *in,
                                                  size_t length, uint16_t *out,
                                                  const uint32_t bit,
                                                  uint32_t *outsum) {
  __m256i sum = _mm256_setzero_si256();
  __m256i carry = _mm256_setzero_si256();
  size_t k;
  for (k = 0; k < length / SIMDBlockSize_u16; ++k) {
    simdunpack_u16_delta_carry(in, out, bit, &carry, &sum);
    out += SIMDBlockSize_u16;
    in += bit;
  }
  /* 256-bit horizontal reduction */
  __m128i lo = _mm256_castsi256_si128(sum);
  __m128i hi = _mm256_extracti128_si256(sum, 1);
  __m128i s = _mm_add_epi32(lo, hi);
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(1,0,3,2)));
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(2,3,0,1)));

  uint32_t finalsum = (uint32_t)_mm_cvtsi128_si32(s);

  /* Tail: scalar un-zigzag + un-delta seeded with the broadcast-carry's
     value (every lane of `carry` holds the same uint16). */
  size_t remainder = length % SIMDBlockSize_u16;
  if (remainder > 0) {
    in = simdunpack_shortlength_u16(in, remainder, out, bit);
    uint16_t prev = (uint16_t)_mm256_extract_epi16(carry, 0);
    size_t i;
    for (i = 0; i < remainder; ++i) {
      uint16_t delta = ZigzagDec16_simdcomp(out[i]);
      uint16_t cur = (uint16_t)(prev + delta);
      finalsum += cur;
      prev = cur;
    }
  }
  *outsum = finalsum;
  return in;
}

